DROP TABLE IF EXISTS `fox_good_lists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_good_lists` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `product_id` bigint(20) NOT NULL DEFAULT '0',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `name` varchar(255) DEFAULT NULL COMMENT '标识',
  `logo` varchar(500) DEFAULT NULL COMMENT 'logo',
  `lang` varchar(50) DEFAULT NULL COMMENT '主要语言',
  `content` text COMMENT '内容描述',
  `sort` int(11) DEFAULT '0' COMMENT '排序',
  `views` int(10) DEFAULT '0' COMMENT '浏览次数',
  `status` tinyint(1) unsigned DEFAULT '1' COMMENT '状态(1:禁用,2:启用)',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  `play_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '玩法周期',
  `play_price` decimal(20,8) NOT NULL DEFAULT '0.00000000' COMMENT '金额最小值',
  `max_price` decimal(20,8) DEFAULT '0.00000000' COMMENT '金额最大值',
  `play_rate` decimal(20,8) NOT NULL DEFAULT '0.00000000' COMMENT '回报率',
  `annual_rate` varchar(50) NOT NULL DEFAULT '3%~8%' COMMENT '年化展示，如3%-8%',
  `can_buy` int(10) DEFAULT '0' COMMENT '限购，0不限制',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8 COMMENT='理财商品列表';
