DROP TABLE IF EXISTS `fox_ieo_lists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_ieo_lists` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `product_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '对应币种',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `coin_title` varchar(255) DEFAULT NULL COMMENT '币名称',
  `logo` varchar(500) DEFAULT NULL COMMENT 'logo',
  `lang` varchar(50) DEFAULT NULL COMMENT '对应语言',
  `content` text COMMENT '内容描述',
  `ieo_usdt_price` decimal(20,8) DEFAULT '0.00000000' COMMENT '发行价格U',
  `ieo_btc_price` decimal(20,8) DEFAULT '0.00000000' COMMENT '发行价格B',
  `ieo_eth_price` decimal(20,8) DEFAULT '0.00000000' COMMENT '发行价格E',
  `ieo_num` bigint(20) DEFAULT '0' COMMENT '发行总量',
  `start_time` int(11) DEFAULT NULL COMMENT '开始时间',
  `end_time` int(11) DEFAULT NULL COMMENT '结束时间',
  `ieo_site` varchar(255) DEFAULT NULL COMMENT '官网',
  `ieo_link` varchar(255) DEFAULT NULL COMMENT '白皮书链接',
  `sort` int(11) DEFAULT '0' COMMENT '排序',
  `status` tinyint(1) unsigned DEFAULT '1' COMMENT '状态(1:禁用,2:启用)',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`),
  KEY `product_id` (`product_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COMMENT='IEO产品表';
/*!40101 SET character_set_client = @saved_cs_client */;

