INSERT INTO `fox_ieo_lists` VALUES (1,6,'IEO','YARD','','en-us','&lt;p&gt;Solyard is a new type of leveraged mining aggregate revenue platform in the Solana ecosystem. It provides users with a safe and stable aggregate revenue function, as well as leveraged mining and lending functions, which greatly improves the user&amp;#39;s asset utilization and rate of return.&lt;/p&gt;\n',0.42000000,0.00000868,0.00012079,30000000,1627574400,1669823999,'https://solyard.finance/','https://solyard.finance/',0,1,'',1625077562,1634651016,NULL);
