DROP TABLE IF EXISTS `fox_kline_data`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_kline_data` (
  `id` bigint(32) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `ch` varchar(100) CHARACTER SET utf32 NOT NULL DEFAULT '' COMMENT '交易对字符串',
  `type` varchar(50) NOT NULL DEFAULT '0' COMMENT '配对',
  `period` varchar(50) NOT NULL DEFAULT '0' COMMENT '时间粒度 1min, 5min, 15min, 30min, 60min, 4hour, 1day, 1mon, 1week, 1year',
  `symbol` varchar(50) NOT NULL DEFAULT '0' COMMENT '交易对',
  `open` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '开盘价格',
  `close` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '闭盘价格',
  `high` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '最高价格',
  `low` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '最低价格',
  `amount` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '成交量',
  `count` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '成交笔数',
  `vol` decimal(20,8) unsigned NOT NULL DEFAULT '0.00000000' COMMENT '成交额, 即 sum(每一笔成交价 * 该笔的成交量)',
  `time` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '时间',
  `create_time` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '时间',
  `update_time` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `type` (`type`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=131 DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT COMMENT='K线图数据';
/*!40101 SET character_set_client = @saved_cs_client */;

