--
-- Table structure for table `fox_lang_lists`
--

DROP TABLE IF EXISTS `fox_lang_lists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_lang_lists` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `item` varchar(50) NOT NULL COMMENT '所属类型',
  `item_id` bigint(20) DEFAULT '0' COMMENT '对应ID',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `logo` varchar(500) DEFAULT NULL COMMENT 'logo',
  `lang` varchar(50) DEFAULT NULL COMMENT '对应语言',
  `content` text COMMENT '内容描述',
  `status` tinyint(1) unsigned DEFAULT '1' COMMENT '状态(1:禁用,2:启用)',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`),
  KEY `item` (`item`),
  KEY `item_id` (`item_id`),
  KEY `lang` (`lang`)
) ENGINE=InnoDB AUTO_INCREMENT=1445 DEFAULT CHARSET=utf8 COMMENT='多语言对应表';
/*!40101 SET character_set_client = @saved_cs_client */;

