--
-- Table structure for table `fox_loan_lists`
--

DROP TABLE IF EXISTS `fox_loan_lists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_loan_lists` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(255) NOT NULL DEFAULT '' COMMENT '默认语言产品名称',
  `description` text COMMENT '默认语言产品描述',
  `logo` varchar(500) NOT NULL DEFAULT '' COMMENT '产品图片',
  `min_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '最小贷款金额',
  `max_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '最大贷款金额',
  `interest_rate` decimal(10,4) NOT NULL DEFAULT '0.0000' COMMENT '年化利率(%)',
  `repayment_period` int(11) NOT NULL DEFAULT '0' COMMENT '还款周期(天)',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态:1启用 0禁用',
  `sort` int(11) NOT NULL DEFAULT '0' COMMENT '排序',
  `lang` varchar(20) NOT NULL DEFAULT 'zh-cn' COMMENT '默认语言',
  `create_time` int(11) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` int(11) NOT NULL DEFAULT '0' COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_status_sort` (`status`,`sort`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COMMENT='贷款产品表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `fox_loan_lists`
--

