DROP TABLE IF EXISTS `fox_loan_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_loan_order` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `uid` int(11) NOT NULL DEFAULT '0' COMMENT '用户ID',
  `loan_id` int(11) NOT NULL DEFAULT '0' COMMENT '贷款产品ID',
  `amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '申请金额',
  `interest_rate` decimal(10,4) NOT NULL DEFAULT '0.0000' COMMENT '年化利率快照(%)',
  `repayment_period` int(11) NOT NULL DEFAULT '0' COMMENT '还款周期快照(天)',
  `total_interest` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '总利息',
  `total_repayment` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '总应还金额',
  `real_name` varchar(100) NOT NULL DEFAULT '' COMMENT '真实姓名',
  `id_number` varchar(100) NOT NULL DEFAULT '' COMMENT '证件号',
  `phone` varchar(30) NOT NULL DEFAULT '' COMMENT '手机号',
  `id_card_front` varchar(500) NOT NULL DEFAULT '' COMMENT '证件正面',
  `id_card_back` varchar(500) NOT NULL DEFAULT '' COMMENT '证件反面',
  `status` int(11) NOT NULL DEFAULT '0' COMMENT '状态:-1已取消 0待审核 1已放款 2已拒绝 4已结清 5已逾期',
  `admin_id` int(11) NOT NULL DEFAULT '0' COMMENT '审核管理员ID',
  `review_remark` varchar(500) NOT NULL DEFAULT '' COMMENT '审核备注',
  `review_time` int(11) NOT NULL DEFAULT '0' COMMENT '审核时间',
  `loan_time` int(11) NOT NULL DEFAULT '0' COMMENT '放款时间',
  `due_time` int(11) NOT NULL DEFAULT '0' COMMENT '到期时间',
  `repayment_time` int(11) NOT NULL DEFAULT '0' COMMENT '还款时间',
  `overdue_time` int(11) NOT NULL DEFAULT '0' COMMENT '逾期时间',
  `create_time` int(11) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` int(11) NOT NULL DEFAULT '0' COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_uid_status` (`uid`,`status`),
  KEY `idx_loan_id` (`loan_id`),
  KEY `idx_due_time_status` (`due_time`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COMMENT='贷款申请订单表';
