--
-- Table structure for table `fox_order_seconds`
--

DROP TABLE IF EXISTS `fox_order_seconds`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_order_seconds` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `uid` bigint(20) NOT NULL COMMENT '用户ID',
  `product_id` bigint(20) NOT NULL COMMENT '产品ID',
  `op_style` tinyint(3) NOT NULL DEFAULT '0' COMMENT '买涨跌:1涨,2跌',
  `op_number` decimal(10,4) DEFAULT NULL COMMENT '手数/数量',
  `start_price` decimal(20,8) DEFAULT NULL COMMENT '入仓价格',
  `end_price` decimal(20,8) DEFAULT '0.00000000' COMMENT '平仓价格',
  `create_time` int(11) DEFAULT NULL COMMENT '建仓时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  `orders_time` int(11) DEFAULT '0' COMMENT '平仓时间',
  `op_status` tinyint(3) DEFAULT '0' COMMENT '状态:0交易,1平仓',
  `play_time` int(11) DEFAULT '0' COMMENT '秒数',
  `play_prop` int(11) DEFAULT '0' COMMENT '盈利率',
  `true_fee` decimal(20,8) DEFAULT '0.00000000' COMMENT '赢利率计算后',
  `all_fee` decimal(20,8) DEFAULT NULL COMMENT '最终赢亏值',
  `sx_fee` decimal(10,4) DEFAULT '0.0000' COMMENT '手续费',
  `order_no` varchar(40) DEFAULT NULL COMMENT '订单编号',
  `display` tinyint(3) DEFAULT '0' COMMENT '0,可查询，1不可查询',
  `is_win` tinyint(3) DEFAULT '0' COMMENT '是否盈利1盈利2亏损3无效',
  `kong_type` tinyint(1) DEFAULT '0' COMMENT '0不空1盈利2亏损',
  `status` tinyint(3) DEFAULT '0' COMMENT '状态',
  `remark` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `is_win` (`is_win`),
  KEY `uid` (`uid`),
  KEY `product_id` (`product_id`)
) ENGINE=InnoDB AUTO_INCREMENT=346 DEFAULT CHARSET=utf8 COMMENT='期权订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

