--
-- Table structure for table `fox_order_winer`
--

DROP TABLE IF EXISTS `fox_order_winer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_order_winer` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `winer_id` bigint(20) DEFAULT '0' COMMENT '矿机ID',
  `product_id` bigint(20) DEFAULT '0' COMMENT '产品ID',
  `uid` bigint(20) DEFAULT '0' COMMENT 'UID',
  `buy_account` decimal(20,8) DEFAULT '0.00000000' COMMENT '购买金额',
  `time` int(10) DEFAULT '0' COMMENT '结算周期',
  `lock` int(10) DEFAULT '0' COMMENT '已结算周期',
  `min_rate` decimal(20,8) DEFAULT '0.00000000' COMMENT '回报率小',
  `max_rate` decimal(20,8) DEFAULT '0.00000000' COMMENT '回报率大',
  `type` tinyint(1) DEFAULT '0' COMMENT '状态:0正常1冻结',
  `status` tinyint(1) unsigned DEFAULT '1' COMMENT '状态(1:结算中,2:已完成)',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  `lock_time` int(11) DEFAULT '0' COMMENT '结算时间',
  `rate_account` decimal(20,8) DEFAULT '0.00000000' COMMENT '已收益',
  PRIMARY KEY (`id`),
  KEY `winer_id` (`winer_id`),
  KEY `uid` (`uid`),
  KEY `status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

