--
-- Table structure for table `fox_product_lists`
--

DROP TABLE IF EXISTS `fox_product_lists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fox_product_lists` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `cate_id` int(11) DEFAULT NULL COMMENT '分类ID',
  `title` varchar(20) NOT NULL COMMENT '产品名称',
  `logo` varchar(500) DEFAULT NULL COMMENT '产品图标',
  `titles` varchar(255) DEFAULT NULL COMMENT '产品别称',
  `name` varchar(100) DEFAULT NULL COMMENT '基于',
  `code` varchar(100) DEFAULT NULL COMMENT '代码识别',
  `base` tinyint(2) unsigned DEFAULT '0' COMMENT '基础币',
  `withdraw_min_num` decimal(20,8) DEFAULT '0.00000000' COMMENT '提币最小值',
  `withdraw_max_num` decimal(20,8) DEFAULT '0.00000000' COMMENT '提币最大值',
  `withdraw_sx_fee` decimal(10,4) DEFAULT '0.0000' COMMENT '提币手续费',
  `withdraw_erc_sxf` decimal(10,4) DEFAULT '0.0000',
  `withdraw_trc_sxf` decimal(10,4) DEFAULT '0.0000',
  `withdraw_omni_sxf` decimal(10,4) DEFAULT '0.0000',
  `withdraw_day_num` int(11) DEFAULT '0' COMMENT '每天提币次数，0不限',
  `withdraw_num_max` decimal(20,8) DEFAULT '0.00000000' COMMENT '最大数分限',
  `withdraw_num_sxf` decimal(10,4) DEFAULT '0.0000' COMMENT '最大限加收手续费',
  `trc_address` varchar(255) DEFAULT NULL COMMENT 'Trc充值',
  `erc_address` varchar(255) DEFAULT NULL COMMENT 'Erc20充值',
  `omni_address` varchar(255) DEFAULT NULL COMMENT 'Omni充值',
  `bsc_address` varchar(255) DEFAULT '',
  `pol_address` varchar(255) DEFAULT '',
  `base_address` varchar(255) DEFAULT '',
  `pay_address` varchar(255) DEFAULT NULL COMMENT '充币地址',
  `pay_time` int(11) unsigned DEFAULT '0' COMMENT '设置时间',
  `open` decimal(30,8) DEFAULT '0.00000000' COMMENT 'open',
  `close` decimal(30,8) DEFAULT '0.00000000' COMMENT 'close',
  `high` decimal(30,8) DEFAULT '0.00000000' COMMENT 'high',
  `low` decimal(30,8) DEFAULT '0.00000000' COMMENT 'low',
  `change` decimal(10,4) DEFAULT '0.0000' COMMENT 'change',
  `amount` decimal(30,8) DEFAULT '0.00000000' COMMENT 'amount',
  `volume` decimal(30,8) DEFAULT '0.00000000' COMMENT 'volume',
  `count` bigint(20) DEFAULT '0' COMMENT 'count',
  `last_price` decimal(30,8) DEFAULT '0.00000000' COMMENT '价值',
  `vol_rand` decimal(20,8) DEFAULT NULL COMMENT '随机值',
  `is_kong` tinyint(1) unsigned DEFAULT '0' COMMENT '空气币(0:否,1:是)',
  `kong_min` decimal(20,8) DEFAULT '0.00000000' COMMENT '空气低',
  `kong_max` decimal(20,8) DEFAULT '0.00000000' COMMENT '空气高',
  `kong_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '1涨2跌',
  `kong_zero` tinyint(3) DEFAULT '6' COMMENT '空小数位',
  `op_kong_min` decimal(20,8) DEFAULT '0.00000000' COMMENT '风控低',
  `op_kong_max` decimal(20,8) DEFAULT '0.00000000' COMMENT '风控高',
  `types` varchar(500) DEFAULT NULL COMMENT '资产类型',
  `sort` int(11) DEFAULT '0' COMMENT '排序',
  `ishome` tinyint(1) unsigned DEFAULT '0' COMMENT '首页显示',
  `status` tinyint(1) unsigned DEFAULT '1' COMMENT '状态(0:禁用,1:启用)',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  `ex_sx_fee` decimal(10,4) DEFAULT '0.0000' COMMENT '币币交易手续费',
  `ex_sell_min` decimal(20,8) DEFAULT '0.00000000' COMMENT '币币最低卖出量',
  `ex_buy_min` decimal(20,8) DEFAULT '0.00000000' COMMENT '币币最低买入量',
  `le_sx_fee` decimal(10,4) DEFAULT '0.0000' COMMENT '合约交易手续费',
  `le_day_sx_fee` decimal(10,4) unsigned DEFAULT '0.0000' COMMENT '合约隔夜手续费',
  `le_no_sx_fee` decimal(10,4) unsigned DEFAULT '0.0000' COMMENT '合约违约手续费',
  `le_play_time` varchar(255) DEFAULT NULL COMMENT '合约玩法杠杆',
  `le_play_type` tinyint(2) unsigned DEFAULT '1' COMMENT '止盈止亏功能，1打开',
  `le_order_rate` int(10) unsigned DEFAULT '0' COMMENT '合约风险率',
  `op_sx_fee` decimal(10,4) DEFAULT NULL COMMENT '期权手续费',
  `op_play_time` varchar(255) DEFAULT NULL COMMENT '期权玩法时间段',
  `op_play_price` varchar(255) DEFAULT NULL COMMENT '期权玩法价格段',
  `op_play_prop` varchar(255) DEFAULT NULL COMMENT '期权玩法盈亏比例',
  `op_play_down` varchar(255) DEFAULT NULL,
  `op_play_max` int(10) unsigned DEFAULT '0' COMMENT '期权最大持仓笔数',
  `op_order_min` int(10) unsigned DEFAULT '1' COMMENT '期权最小购买',
  `op_order_max` int(10) unsigned DEFAULT '0' COMMENT '期权最大购买,0不限制',
  `op_order_kong` int(5) unsigned DEFAULT '50' COMMENT '期权风控率',
  `withdraw_member` tinyint(2) unsigned DEFAULT '0' COMMENT '用户提现0否1是',
  `isIeorg` tinyint(2) DEFAULT '0' COMMENT 'IEO认购',
  `popularity_sort` int(11) NOT NULL DEFAULT '0',
  `withdraw_bsc_sxf` decimal(10,2) NOT NULL DEFAULT '0.00',
  `withdraw_pol_sxf` decimal(10,2) NOT NULL DEFAULT '0.00',
  `withdraw_base_sxf` decimal(10,2) NOT NULL DEFAULT '0.00',
  PRIMARY KEY (`id`),
  KEY `cate_id` (`cate_id`),
  KEY `code` (`code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT COMMENT='产品列表';
/*!40101 SET character_set_client = @saved_cs_client */;

